import{_ as a,o as s,c as t,ae as r}from"./chunks/framework.B6gjLfeO.js";const m=JSON.parse('{"title":"KPI Alerts for Analysis Dashboards","description":"","frontmatter":{"title":"KPI Alerts for Analysis Dashboards","slug":"kpi-alerts-for-analysis-dashboards"},"headers":[],"relativePath":"account-hub/kpi-alerts-for-analysis-dashboards.md","filePath":"account-hub/kpi-alerts-for-analysis-dashboards.md"}'),i={name:"account-hub/kpi-alerts-for-analysis-dashboards.md"};function o(n,e,l,d,c,h){return s(),t("div",null,[...e[0]||(e[0]=[r('<p>Branch has added KPI alerts to Analysis Dashboards, giving you the ability to monitor your most important metrics and receive automatic notifications when key thresholds are met or unexpected changes occur.</p><h2 id="what-s-new" tabindex="-1">What’s new? <a class="header-anchor" href="#what-s-new" aria-label="Permalink to &quot;What’s new?&quot;">​</a></h2><p>Analysis Dashboards now include the following functionality:</p><ul><li><strong>Alerts on widgets</strong>: Create alerts directly on dashboard widgets to monitor specific KPIs.</li><li><strong>Flexible scheduling</strong>: Configure when and how often alerts check your data. The default is daily, at 09:00 UTC.</li><li><strong>Team collaboration</strong>: Add multiple team members as alert subscribers and include custom messages to provide context.</li><li><strong>Management capabilities</strong>: Manage alerts directly from the widget level, where you can edit conditions, add or remove subscribers, or delete alerts.</li></ul><h2 id="benefits" tabindex="-1">Benefits <a class="header-anchor" href="#benefits" aria-label="Permalink to &quot;Benefits&quot;">​</a></h2><p>KPI alerts enable you to have:</p><ul><li><strong>Proactive monitoring</strong>: Automatically track important metrics without manual dashboard checks.</li><li><strong>Faster response times</strong>: Get notified immediately when something important happens.</li><li><strong>Team visibility</strong>: Keep your entire team informed by adding multiple subscribers to receive alerts.</li></ul><h2 id="access" tabindex="-1">Access <a class="header-anchor" href="#access" aria-label="Permalink to &quot;Access&quot;">​</a></h2><p>KPI alerts are available to all Analysis Dashboard users.</p><p>Analysis Dashboards represent the next evolution in Branch&#39;s marketing analytics and reporting. They unify data from ads, social media, SEO, email, and more into a single, cohesive experience.</p><p>Access to this feature is currently being rolled out to customers in phases as part of Branch&#39;s new platform experience.</p><h2 id="learn-more" tabindex="-1">Learn more <a class="header-anchor" href="#learn-more" aria-label="Permalink to &quot;Learn more&quot;">​</a></h2><p>For detailed instructions on setting up and managing KPI alerts, visited our dedicated <a href="./analysis-dashboards.html#set-kpi-alert">Analysis Dashboards guide</a>.</p>',13)])])}const p=a(i,[["render",o]]);export{m as __pageData,p as default};
